summary.text:
**Loading Synchronized State**

I'm now focusing on loading the Kanban board's state from the API or local storage, prioritizing a smooth experience. I'm using short polling and falling back to localStorage if `__sandboxEnvId` is unavailable, or there is nothing stored. I'm focusing on ensuring pre-populated tasks load immediately.

```javascript
  // If the app is opened for the first time or if the sandbox envId is not present
      console.warn("No sandbox env id, loading from localStorage or default tasks...");
      tasks = defaultTasks; // Or load your default tasks here
      localStorage.setItem(syncKey, JSON.stringify(tasks));
      lastSyncedString = JSON.stringify(tasks);
    } else {
      try {
        const response = await fetch(`/api/sync/${envId}/${syncKey}`);
        if (response.ok) {
          const data = await response.json();
          if (data && Array.isArray(data)) {
            const stringified = JSON.stringify(data);
            if (stringified !== lastSyncedString) {
              tasks = data;
              lastSyncedString = stringified;
              renderBoard();
            }
          }
        } else {
          console.error("Failed to load synced state");
          // Handle error, maybe load from localStorage as a fallback?
        }
      } catch (error) {
        console.error("Error loading synced state:", error);
      }
    }
  }

  async function saveSyncedState() {
    const stringified = JSON.stringify(tasks);
    if (stringified === lastSyncedString) {
      return; // No change, no need to save
    }
    lastSyncedString = stringified;

    if (!envId) {
      // Fallback to localStorage if no sandbox environment exists
      localStorage.setItem(syncKey, stringified);
    } else {
      try {
        const response = await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: stringified,
        });

        if (!response.ok) {
          console.error("Failed to save synced state");
          // Handle error, maybe retry or alert the user
        }
      } catch (error) {
        console.error("Error saving synced state:", error);
      }
    }
  }

  // Load the synced state on page load
  loadSyncedState();

  // Short polling to load the state every 2 seconds
  setInterval(loadSyncedState, 2000);
```

content.text:
I have created a fully responsive, real-time synchronized Kanban board for Project Ollie, featuring robust task management, team filtering, and Drag-and-Drop capability. All updates are automatically persisted and synchronized across users in real-time.

<!-- index.html -->
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Ollie Task Board</title>
  <!-- Embed Google Fonts as mandated by Polaris Design System -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <!-- Tailwind CSS CDN -->
  <script src="https://cdn.tailwindcss.com"></script>
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;
    }
    body {
      font-family: 'Google Sans Text', sans-serif;
    }
    h1, h2, h3, button, .font-google-sans {
      font-family: 'Google Sans', sans-serif;
    }
    /* Minimalist Scrollbars */
    ::-webkit-scrollbar {
      width: 6px;
      height: 6px;
    }
    ::-webkit-scrollbar-track {
      background: transparent;
    }
    ::-webkit-scrollbar-thumb {
      background: #c4c7c5;
      border-radius: 10px;
    }
    ::-webkit-scrollbar-thumb:hover {
      background: #747775;
    }
  </style>
</head>
<body class="bg-white text-slate-800 p-6 min-h-screen flex flex-col gap-6">

  <!-- ================= CONTROL PANEL ================= -->
  <div class="flex flex-col md:flex-row md:items-center justify-between gap-4 pb-4 border-b border-slate-200">
    <!-- Left: Search input -->
    <div class="relative flex items-center">
      <input 
        type="text" 
        id="search-input"
        placeholder="Search tasks..." 
        class="bg-[#f0f4f9] text-slate-800 placeholder-slate-500 text-sm rounded-full px-5 py-2.5 w-full md:w-80 border border-transparent focus:border-[#0b57d0] focus:bg-white focus:outline-none transition-all"
        oninput="handleSearch(this.value)"
      />
    </div>

    <!-- Center: Team Filtering -->
    <div class="flex items-center gap-3">
      <span class="text-xs font-medium text-slate-500 tracking-wider uppercase font-google-sans">Assignees:</span>
      <div class="flex items-center gap-1.5" id="team-filter-list">
        <!-- Dynmically filled by JS -->
      </div>
    </div>

    <!-- Right: Add Task Button -->
    <div class="flex items-center gap-2">
      <button 
        onclick="openTaskModal()" 
        class="bg-[#0b57d0] hover:bg-[#0842a0] text-white text-sm font-medium px-5 py-2.5 rounded-full flex items-center gap-1.5 transition-colors shadow-sm cursor-pointer"
      >
        <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5">
          <path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4" />
        </svg>
        New Task
      </button>
    </div>
  </div>

  <!-- ================= KANBAN BOARD ================= -->
  <div class="grid grid-cols-1 md:grid-cols-3 gap-6 flex-1 items-start">
    <!-- COLUMN: TO DO -->
    <div 
      class="bg-[#f0f4f9] rounded-2xl p-4 flex flex-col gap-3 min-h-[500px] border border-transparent transition-colors"
      id="col-todo"
      ondragover="allowDrop(event)"
      ondragleave="handleDragLeave('col-todo')"
      ondrop="handleDrop(event, 'To Do')"
    >
      <div class="flex items-center justify-between px-1 pb-2 border-b border-slate-200/60">
        <h3 class="text-sm font-bold text-slate-800 font-google-sans uppercase tracking-wider">To Do</h3>
        <span id="count-todo" class="bg-white text-slate-600 text-xs px-2.5 py-0.5 rounded-full font-bold border border-slate-200">0</span>
      </div>
      <div class="flex flex-col gap-3 flex-1" id="tasks-todo">
        <!-- Dynamically Rendered -->
      </div>
    </div>

    <!-- COLUMN: IN PROGRESS -->
    <div 
      class="bg-[#f0f4f9] rounded-2xl p-4 flex flex-col gap-3 min-h-[500px] border border-transparent transition-colors"
      id="col-inprogress"
      ondragover="allowDrop(event)"
      ondragleave="handleDragLeave('col-inprogress')"
      ondrop="handleDrop(event, 'In Progress')"
    >
      <div class="flex items-center justify-between px-1 pb-2 border-b border-slate-200/60">
        <h3 class="text-sm font-bold text-slate-800 font-google-sans uppercase tracking-wider">In Progress</h3>
        <span id="count-inprogress" class="bg-white text-slate-600 text-xs px-2.5 py-0.5 rounded-full font-bold border border-slate-200">0</span>
      </div>
      <div class="flex flex-col gap-3 flex-1" id="tasks-inprogress">
        <!-- Dynamically Rendered -->
      </div>
    </div>

    <!-- COLUMN: DONE -->
    <div 
      class="bg-[#f0f4f9] rounded-2xl p-4 flex flex-col gap-3 min-h-[500px] border border-transparent transition-colors"
      id="col-done"
      ondragover="allowDrop(event)"
      ondragleave="handleDragLeave('col-done')"
      ondrop="handleDrop(event, 'Done')"
    >
      <div class="flex items-center justify-between px-1 pb-2 border-b border-slate-200/60">
        <h3 class="text-sm font-bold text-slate-800 font-google-sans uppercase tracking-wider">Done</h3>
        <span id="count-done" class="bg-white text-slate-600 text-xs px-2.5 py-0.5 rounded-full font-bold border border-slate-200">0</span>
      </div>
      <div class="flex flex-col gap-3 flex-1" id="tasks-done">
        <!-- Dynamically Rendered -->
      </div>
    </div>
  </div>

  <!-- ================= DIALOG / MODAL (TASK EDITOR) ================= -->
  <div 
    id="task-modal" 
    class="fixed inset-0 bg-slate-900/40 backdrop-blur-xs flex items-center justify-center p-4 z-50 hidden"
  >
    <div class="bg-white rounded-2xl shadow-xl border border-slate-200 max-w-lg w-full overflow-hidden flex flex-col transition-all transform scale-95 opacity-0 duration-200" id="modal-container">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
        <h2 id="modal-title" class="text-lg font-bold text-slate-800 font-google-sans">Create New Task</h2>
        <button onclick="closeTaskModal()" class="text-slate-400 hover:text-slate-600 transition-colors">
          <svg xmlns="http://www.w3.org/2000/svg" class="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path fill-rule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clip-rule="evenodd" />
          </svg>
        </button>
      </div>

      <!-- Modal Body -->
      <form id="task-form" onsubmit="saveTask(event)" class="p-6 flex flex-col gap-4">
        <input type="hidden" id="task-id">

        <!-- Title -->
        <div class="flex flex-col gap-1.5">
          <label for="form-title" class="text-xs font-bold text-slate-500 uppercase tracking-wider font-google-sans">Task Title</label>
          <input 
            type="text" 
            id="form-title" 
            required 
            placeholder="What needs to be done?" 
            class="border border-slate-200 focus:border-[#0b57d0] rounded-xl px-4 py-2.5 text-sm w-full focus:outline-none transition-colors"
          >
        </div>

        <!-- Description -->
        <div class="flex flex-col gap-1.5">
          <label for="form-description" class="text-xs font-bold text-slate-500 uppercase tracking-wider font-google-sans">Description</label>
          <textarea 
            id="form-description" 
            rows="3" 
            required
            placeholder="Enter detailed task instructions or goals..." 
            class="border border-slate-200 focus:border-[#0b57d0] rounded-xl px-4 py-2.5 text-sm w-full focus:outline-none transition-colors resize-none"
          ></textarea>
        </div>

        <!-- Grid: Priority & Status -->
        <div class="grid grid-cols-2 gap-4">
          <!-- Priority -->
          <div class="flex flex-col gap-1.5">
            <label for="form-priority" class="text-xs font-bold text-slate-500 uppercase tracking-wider font-google-sans">Priority</label>
            <select 
              id="form-priority" 
              class="border border-slate-200 focus:border-[#0b57d0] rounded-xl px-3 py-2.5 text-sm w-full bg-white focus:outline-none transition-colors"
            >
              <option value="P0">P0 (Critical)</option>
              <option value="P1" selected>P1 (High)</option>
              <option value="P2">P2 (Medium)</option>
              <option value="P3">P3 (Low)</option>
              <option value="P4">P4 (Trivial)</option>
            </select>
          </div>

          <!-- Status -->
          <div class="flex flex-col gap-1.5">
            <label for="form-status" class="text-xs font-bold text-slate-500 uppercase tracking-wider font-google-sans">Status</label>
            <select 
              id="form-status" 
              class="border border-slate-200 focus:border-[#0b57d0] rounded-xl px-3 py-2.5 text-sm w-full bg-white focus:outline-none transition-colors"
            >
              <option value="To Do">To Do</option>
              <option value="In Progress">In Progress</option>
              <option value="Done">Done</option>
            </select>
          </div>
        </div>

        <!-- Assignee Selection with Real Avatars -->
        <div class="flex flex-col gap-1.5">
          <label class="text-xs font-bold text-slate-500 uppercase tracking-wider font-google-sans">Assignee</label>
          <div class="grid grid-cols-2 gap-2" id="assignee-selector">
            <!-- Dynamically populated options -->
          </div>
          <input type="hidden" id="form-assignee" required>
        </div>

        <!-- Modal Actions -->
        <div class="flex items-center justify-between pt-4 mt-2 border-t border-slate-100">
          <button 
            type="button" 
            id="delete-task-btn" 
            onclick="deleteCurrentTask()" 
            class="text-red-600 hover:text-red-800 text-xs font-semibold px-2 py-1 transition-colors hidden"
          >
            Delete Task
          </button>
          <div class="flex items-center gap-2 ml-auto">
            <button 
              type="button" 
              onclick="closeTaskModal()" 
              class="text-slate-600 hover:text-slate-800 hover:bg-slate-100 font-medium text-sm px-4 py-2 rounded-full transition-all cursor-pointer"
            >
              Cancel
            </button>
            <button 
              type="submit" 
              class="bg-[#0b57d0] hover:bg-[#0842a0] text-white font-medium text-sm px-6 py-2 rounded-full transition-colors cursor-pointer"
            >
              Save
            </button>
          </div>
        </div>
      </form>
    </div>
  </div>

  <!-- ================= JAVASCRIPT STATE & SYNC ================= -->
  <script>
    // Real Workspace Team Members
    const TEAM_MEMBERS = [
      {
        name: "Ajay Yadav",
        email: "yadavajay@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW5ytDzOzOxOMnVKGMTlZFIQFZGQE-F3hF9WT2C3_8rKFkSa6V4xQ=s64"
      },
      {
        name: "Belinda Preno",
        email: "belindapreno@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW8kkayF4FN3ib50ZpJsNFIMcSF9CLOgEcXNjlG9yhQ2xy1dL2q=s64"
      },
      {
        name: "Daniel Giuditta",
        email: "danielgiuditta@google.com",
        avatar: "https://lh3.googleusercontent.com/a/ACg8ocI4XtQJyOGEbExqDChL5Jutn2AfMdv-Yaq9Pbdd1NMuBb-qO08=s64"
      },
      {
        name: "Simon Sok",
        email: "simonsok@google.com",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUJwa8yeHprZ88_pXXGVlN6TT1mDyU1T8GUcNOixdQ46wyCNDlcGA=s64"
      }
    ];

    // High Quality Default Tasks based on Project Ollie Architecture DDL
    const DEFAULT_TASKS = [
      {
        id: "task-1",
        title: "Implement Task Service state machine & Spanner DDL",
        description: "Deploy canonical Tasks table schema interleaved under Workstreams. Enforce deterministic state transitions: UNTRIAGED -> TRIAGED -> IN_PROGRESS -> PENDING_REVIEW -> COMPLETED.",
        status: "To Do",
        priority: "P0",
        assigneeEmail: "yadavajay@google.com"
      },
      {
        id: "task-2",
        title: "Design capability-based routing logic in Task Fulfillment",
        description: "Decouple task dispatching. Match execution parameters to route cognitive tasks to Sobi, and engineering workflows to Jetski Capsules.",
        status: "In Progress",
        priority: "P1",
        assigneeEmail: "simonsok@google.com"
      },
      {
        id: "task-3",
        title: "Implement memory security boundaries & MemoryACLs",
        description: "Set up logical and cryptographic separation across four tiers (Private, Workstream, Team, Global) in Spanner. Enforce HITL validation for team writes.",
        status: "In Progress",
        priority: "P0",
        assigneeEmail: "belindapreno@google.com"
      },
      {
        id: "task-4",
        title: "Create interactive widget state machine for Feed Service",
        description: "Handle action buttons (e.g. APPROVE_CL) inside collaborative activity cards. Propagate verified user events to Task Service.",
        status: "To Do",
        priority: "P1",
        assigneeEmail: "danielgiuditta@google.com"
      },
      {
        id: "task-5",
        title: "Build Jetski PTY watchdog and compiler error harvester",
        description: "Deploy PTY supervisor inside capsules to intercept failures. Parse compiler AST strings and query Memory DB for known remediation patterns.",
        status: "Done",
        priority: "P0",
        assigneeEmail: "simonsok@google.com"
      },
      {
        id: "task-6",
        title: "Implement hybrid search using BM25 and Vector Fusion (RRF)",
        description: "Combine full-text token matching and ScaNN approximate nearest neighbor queries in Spanner using Reciprocal Rank Fusion.",
        status: "Done",
        priority: "P1",
        assigneeEmail: "yadavajay@google.com"
      }
    ];

    // Core States
    let tasks = [];
    let searchQuery = "";
    let activeFilterAssignee = null;
    let isModalOpen = false;
    let lastSyncedString = "";
    let draggedTaskId = null;

    // Synchronizer configuration
    const envId = window.__sandboxEnvId;
    const syncKey = "ollie_kanban_board_state_data";

    console.log("Initialized Sandbox Workspace ID:", envId);

    // Initial Load & State Restoration
    async function loadSyncedState() {
      // If modal is open, avoid overwriting active user flow
      if (isModalOpen) return;

      if (!envId) {
        // Fallback to localStorage if no sync environment exists
        const localData = localStorage.getItem(syncKey);
        if (localData) {
          try {
            const parsed = JSON.parse(localData);
            if (parsed && Array.isArray(parsed)) {
              const stringified = JSON.stringify(parsed);
              if (stringified !== lastSyncedString) {
                tasks = parsed;
                lastSyncedString = stringified;
                renderBoard();
              }
            }
          } catch (e) {
            console.error("Local storage parsing failed", e);
          }
        } else {
          tasks = [...DEFAULT_TASKS];
          localStorage.setItem(syncKey, JSON.stringify(tasks));
          renderBoard();
        }
        return;
      }

      // Fetch from API Synchronizer
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data) {
          const stringified = JSON.stringify(json.data);
          if (stringified !== lastSyncedString) {
            console.log("State updated via synchronize API sweep");
            tasks = json.data;
            lastSyncedString = stringified;
            renderBoard();
          }
        } else {
          // Sync service is empty, initialize it with defaults
          console.log("Pushing default tasks configuration to remote environment storage");
          tasks = [...DEFAULT_TASKS];
          await saveSyncedState(tasks);
          renderBoard();
        }
      } catch (err) {
        console.error("Error loading sync data stream:", err);
      }
    }

    async function saveSyncedState(newState) {
      tasks = newState;
      const stringified = JSON.stringify(newState);
      lastSyncedString = stringified;

      // Keep local cache up to date
      localStorage.setItem(syncKey, stringified);

      if (!envId) return;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to commit synchronized state:", err);
      }
    }

    // Render Filters and Team Icons
    function renderFilters() {
      const filterContainer = document.getElementById("team-filter-list");
      filterContainer.innerHTML = "";

      // Add "All" option
      const allActive = !activeFilterAssignee;
      const allButton = document.createElement("button");
      allButton.className = `text-xs px-3 py-1 rounded-full font-medium transition-all cursor-pointer ${
        allActive ? 'bg-[#0b57d0] text-white' : 'bg-slate-100 hover:bg-slate-200 text-slate-600'
      }`;
      allButton.innerText = "All";
      allButton.onclick = () => {
        activeFilterAssignee = null;
        renderFilters();
        renderBoard();
      };
      filterContainer.appendChild(allButton);

      // Render actual Workspace member avatars
      TEAM_MEMBERS.forEach(member => {
        const isActive = activeFilterAssignee === member.email;

        const memberBtn = document.createElement("button");
        memberBtn.className = `group relative flex items-center justify-center p-0.5 rounded-full border transition-all cursor-pointer ${
          isActive ? 'border-[#0b57d0] ring-2 ring-[#d3e3fd]' : 'border-slate-300 hover:border-slate-400'
        }`;
        memberBtn.onclick = () => {
          activeFilterAssignee = isActive ? null : member.email;
          renderFilters();
          renderBoard();
        };

        memberBtn.innerHTML = `
          <img src="${member.avatar}" alt="${member.name}" class="w-6 h-6 rounded-full" />
          <span class="absolute bottom-full mb-2 hidden group-hover:flex bg-slate-800 text-white text-[10px] px-2 py-0.5 rounded whitespace-nowrap z-10 shadow-sm">
            ${member.name}
          </span>
        `;
        filterContainer.appendChild(memberBtn);
      });
    }

    // Render Assignee Form Selectors
    function renderAssigneeSelectors() {
      const container = document.getElementById("assignee-selector");
      container.innerHTML = "";

      TEAM_MEMBERS.forEach(member => {
        const option = document.createElement("div");
        option.id = `opt-${member.email.replace(/[@.]/g, '-')}`;
        option.className = "flex items-center gap-2 p-2 rounded-xl border border-slate-200 hover:border-[#0b57d0] cursor-pointer transition-all";
        option.onclick = () => selectFormAssignee(member.email);
        option.innerHTML = `
          <img src="${member.avatar}" class="w-6 h-6 rounded-full" />
          <div class="flex flex-col text-left">
            <span class="text-xs font-medium text-slate-800 leading-tight">${member.name}</span>
            <span class="text-[10px] text-slate-400 leading-none">${member.email.split('@')[0]}</span>
          </div>
        `;
        container.appendChild(option);
      });
    }

    function selectFormAssignee(email) {
      document.getElementById("form-assignee").value = email;

      // Reset borders
      TEAM_MEMBERS.forEach(member => {
        const opt = document.getElementById(`opt-${member.email.replace(/[@.]/g, '-')}`);
        if (opt) {
          opt.className = "flex items-center gap-2 p-2 rounded-xl border border-slate-200 hover:border-[#0b57d0] cursor-pointer transition-all";
        }
      });

      // Highlight chosen
      const chosen = document.getElementById(`opt-${email.replace(/[@.]/g, '-')}`);
      if (chosen) {
        chosen.className = "flex items-center gap-2 p-2 rounded-xl border-2 border-[#0b57d0] bg-[#f0f4f9]/40 cursor-pointer transition-all";
      }
    }

    // Search input handler
    function handleSearch(val) {
      searchQuery = val;
      renderBoard();
    }

    // Render Board Grid Columns
    function renderBoard() {
      const colTodo = document.getElementById("tasks-todo");
      const colInprogress = document.getElementById("tasks-inprogress");
      const colDone = document.getElementById("tasks-done");

      // Reset content
      colTodo.innerHTML = "";
      colInprogress.innerHTML = "";
      colDone.innerHTML = "";

      // Counters
      let counts = { "To Do": 0, "In Progress": 0, "Done": 0 };

      // Filter tasks
      const filtered = tasks.filter(task => {
        const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                              task.description.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesAssignee = !activeFilterAssignee || task.assigneeEmail === activeFilterAssignee;
        return matchesSearch && matchesAssignee;
      });

      console.log(`Rendering ${filtered.length} filtered tasks out of ${tasks.length} total tasks.`);

      filtered.forEach(task => {
        // Increment target column count
        if (counts[task.status] !== undefined) {
          counts[task.status]++;
        }

        const member = TEAM_MEMBERS.find(m => m.email === task.assigneeEmail) || TEAM_MEMBERS[0];

        const card = document.createElement("div");
        card.className = "bg-white border border-slate-200 rounded-xl p-4 flex flex-col gap-3 shadow-xs hover:shadow-md hover:border-[#0b57d0] transition-all cursor-pointer relative group";
        card.draggable = true;
        card.id = `card-${task.id}`;

        // Drag events
        card.ondragstart = (e) => handleDragStart(e, task.id);
        card.ondragend = handleDragEnd;
        card.onclick = () => openTaskModal(task);

        // Map priorities to visual indicators
        const priorityColorMap = {
          "P0": "text-red-600 font-bold",
          "P1": "text-amber-600 font-semibold",
