              ` : ''}
              ${task.status !== "In Progress" ? `
                <button title="Move to In Progress" onclick="event.stopPropagation(); changeTaskStatus('${task.id}', 'In Progress')" class="p-1 hover:bg-slate-100 rounded text-slate-500">
                  <svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H8m0 0l4 4m-4-4l4-4" />
                  </svg>
                </button>
              ` : ''}
              ${task.status !== "Done" ? `
                <button title="Move to Done" onclick="event.stopPropagation(); changeTaskStatus('${task.id}', 'Done')" class="p-1 hover:bg-slate-100 rounded text-slate-500">
                  <svg xmlns="http://www.w3.org/2000/svg" class="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
