                </button>
              ` : ''}
            </div>

            <div class="flex items-center gap-1.5 ml-auto">
              <span class="text-[10px] text-slate-400 font-medium">${escapeHtml(member.name.split(' ')[0])}</span>
              <img src="${member.avatar}" alt="${member.name}" class="w-5 h-5 rounded-full border border-slate-200" />
            </div>
          </div>
        `;

        if (task.status === "To Do") {
          colTodo.appendChild(card);
        } else if (task.status === "In Progress") {
          colInprogress.appendChild(card);
        } else if (task.status === "Done") {
          colDone.appendChild(card);
        }
      });

      // Update count indicators
      document.getElementById("count-todo").innerText = counts["To Do"];
      document.getElementById("count-inprogress").innerText = counts["In Progress"];
      document.getElementById("count-done").innerText = counts["Done"];
    }

    // Drag and Drop Logic
    function handleDragStart(e, taskId) {
      draggedTaskId = taskId;
      const card = document.getElementById(`card-${taskId}`);
