      document.getElementById(colId).classList.add("bg-[#e2e8f0]");
    }

    function handleDragLeave(colId) {
      document.getElementById(colId).classList.remove("bg-[#e2e8f0]");
    }

    function handleDrop(e, status) {
      e.preventDefault();
      const colId = e.currentTarget.id;
      document.getElementById(colId).classList.remove("bg-[#e2e8f0]");

      const id = e.dataTransfer.getData("text/plain") || draggedTaskId;
      if (id) {
        changeTaskStatus(id, status);
      }
    }

    function changeTaskStatus(id, newStatus) {
      const idx = tasks.findIndex(t => t.id === id);
      if (idx !== -1 && tasks[idx].status !== newStatus) {
        console.log(`Task ${id} moved from '${tasks[idx].status}' to '${newStatus}'`);
        tasks[idx].status = newStatus;
        saveSyncedState(tasks);
        renderBoard();
      }
    }

    // Modal Control Logic
    function openTaskModal(task = null) {
      isModalOpen = true;
      document.getElementById("task-modal").classList.remove("hidden");
      setTimeout(() => {
        document.getElementById("modal-container").classList.remove("scale-95", "opacity-0");
      }, 50);

      renderAssigneeSelectors();

      const deleteBtn = document.getElementById("delete-task-btn");
      if (task) {
        document.getElementById("modal-title").innerText = "Edit Task";
        document.getElementById("task-id").value = task.id;
        document.getElementById("form-title").value = task.title;
        document.getElementById("form-description").value = task.description;
        document.getElementById("form-priority").value = task.priority;
        document.getElementById("form-status").value = task.status;
        selectFormAssignee(task.assigneeEmail);
        deleteBtn.classList.remove("hidden");
      } else {
        document.getElementById("modal-title").innerText = "Create New Task";
        document.getElementById("task-form").reset();
        document.getElementById("task-id").value = "";
        selectFormAssignee(TEAM_MEMBERS[0].email);
        deleteBtn.classList.add("hidden");
      }
    }

    function closeTaskModal() {
      document.getElementById("modal-container").classList.add("scale-95", "opacity-0");
      setTimeout(() => {
        document.getElementById("task-modal").classList.add("hidden");
        isModalOpen = false;
        loadSyncedState(); // Sync up immediately if missed updates
      }, 150);
    }

    // Create or Edit Task Commit
    function saveTask(e) {
      e.preventDefault();

      const taskId = document.getElementById("task-id").value;
      const title = document.getElementById("form-title").value;
      const description = document.getElementById("form-description").value;
      const priority = document.getElementById("form-priority").value;
      const status = document.getElementById("form-status").value;
      const assigneeEmail = document.getElementById("form-assignee").value;

      if (taskId) {
        // Edit flow
        const idx = tasks.findIndex(t => t.id === taskId);
        if (idx !== -1) {
          tasks[idx] = { ...tasks[idx], title, description, priority, status, assigneeEmail };
          console.log("Updated existing task successfully");
        }
      } else {
        // Create Flow
        const newTask = {
          id: "task-" + Date.now(),
          title,
          description,
          priority,
          status,
          assigneeEmail
        };
        tasks.push(newTask);
        console.log("Created new task entry: ", newTask.id);
      }

      saveSyncedState(tasks);
      closeTaskModal();
      renderBoard();
    }

    // Delete Current Task
    function deleteCurrentTask() {
      const taskId = document.getElementById("task-id").value;
      if (taskId && confirm("Are you sure you want to delete this task?")) {
        const initialLen = tasks.length;
        tasks = tasks.filter(t => t.id !== taskId);
        if (tasks.length < initialLen) {
          console.log(`Deleted task: ${taskId}`);
          saveSyncedState(tasks);
        }
        closeTaskModal();
        renderBoard();
      }
    }

    // HTML escape utility to keep app secure against user input injection
    function escapeHtml(str) {
      if (!str) return '';
      return str
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
    }

    // Poll State from Synchronizer every 2 seconds
    renderFilters();
    loadSyncedState();
    setInterval(loadSyncedState, 2000);
  </script>
</body>
