2. Ollie Spanner DDL (Workstreams, WorkstreamMemberships, Tasks, Feeds, FeedComments, ListenerConfigs)
-- ============================================================================
-- 1. WORKSTREAMS CYLINDER
-- Authoritative root tenant table for workspaces and asset bindings.
-- ============================================================================
CREATE TABLE Workstreams (
  workstream_id STRING(64) NOT NULL,
  display_name STRING(256) NOT NULL,
  description STRING(MAX),
  charter_markdown STRING(MAX),
  owner_gaia_id STRING(64) NOT NULL,
  service_account_email STRING(256) NOT NULL,
  associated_google_groups ARRAY<STRING(256)>,
  buganizer_hotlist_ids ARRAY<STRING(64)>,
  shared_drive_id STRING(128),
  chat_space_id STRING(128),
  is_archived BOOL NOT NULL DEFAULT (false),
  create_time TIMESTAMP NOT NULL OPTIONS (allow_commit_timestamp=true),
